const items = $input.all();
return items.map(item => {
  const d = item.json;
  if (d.error || d.statusCode >= 400) {
    return { json: { encontrado: false, mensagem: 'Deal não encontrado' } };
  }
  const deal = d.deal || d;
  return {
    json: {
      encontrado: true,
      deal_id: deal.id,
      title: deal.title,
      status: deal.status,
      temperature: deal.temperature,
      value: deal.value,
      pipeline_name: deal.pipeline_name,
      stage_name: deal.stage_name,
      pipeline_stage_id: deal.pipeline_stage_id,
      contact_name: deal.contact_name,
      company_name: deal.company_name,
      source: deal.source,
      insights: (deal.insights || []).slice(0, 10),
      activities: (deal.activities || []).slice(0, 10)
    }
  };
});
